<?php
namespace App\Models;use App\Core\Database;
final class User{public static function find(int $id):?array{$s=Database::connection()->prepare('SELECT id,name,email,phone,is_active,created_at FROM users WHERE id=?');$s->execute([$id]);return$s->fetch()?:null;}public static function byEmail(string $e):?array{$s=Database::connection()->prepare('SELECT * FROM users WHERE email=? LIMIT 1');$s->execute([strtolower($e)]);return$s->fetch()?:null;}public static function create(array$d):int{$s=Database::connection()->prepare('INSERT INTO users(name,email,phone,password) VALUES(?,?,?,?)');$s->execute([$d['name'],strtolower($d['email']),$d['phone']?:null,password_hash($d['password'],PASSWORD_DEFAULT)]);return(int)Database::connection()->lastInsertId();}public static function assignRole(int$u,string$r):void{$s=Database::connection()->prepare('INSERT IGNORE INTO user_roles(user_id,role_id) SELECT ?,id FROM roles WHERE name=?');$s->execute([$u,$r]);}public static function roles(int$u):array{$s=Database::connection()->prepare('SELECT r.name FROM roles r JOIN user_roles ur ON ur.role_id=r.id WHERE ur.user_id=?');$s->execute([$u]);return array_column($s->fetchAll(),'name');}}
